const normalizeSpoken=(text)=>{let t=text.trim().toLowerCase();t=t.replace(/\b(\d+)\b/g,(m)=>{const n=parseInt(m);if(n>=0&&n<=100&&NW[n])return NW[n];return m;});t=t.replace(/^(the |a |an |uh |um |oh |i said |it's |its |say |it is )/i,'');const fixes={"for":"four","to":"two","too":"two","won":"one","ate":"eight","tree":"three","free":"three","read":"red","blew":"blue","grin":"green","sickle":"circle","squire":"square","try angle":"triangle","hart":"heart","start":"star","wabbit":"rabbit","wion":"lion","fwog":"frog","lellow":"yellow"};if(fixes[t])return fixes[t];for(const[w,r]of Object.entries(fixes))if(t.includes(w)){t=t.replace(w,r);break;}return t.trim();};
const calcAcc=(expected,spoken,alternatives)=>{if(!expected||!spoken)return 0;const e=expected.trim().toLowerCase();const candidates=[normalizeSpoken(spoken),...(alternatives||[]).map(a=>normalizeSpoken(a))];let best=0;for(const b of candidates){if(!b)continue;if(e===b)return 100;if(b.includes(e)){best=Math.max(best,95);continue;}if(e.includes(b)&&b.length>=e.length*0.6){best=Math.max(best,85);continue;}const m=Array.from({length:e.length+1},(_,i)=>Array.from({length:b.length+1},(_,j)=>i===0?j:j===0?i:0));for(let i=1;i<=e.length;i++)for(let j=1;j<=b.length;j++)m[i][j]=e[i-1]===b[j-1]?m[i-1][j-1]:1+Math.min(m[i-1][j],m[i][j-1],m[i-1][j-1]);best=Math.max(best,Math.max(0,Math.round((1-m[e.length][b.length]/Math.max(e.length,b.length))*100)));}return best;};
