const useSpeech=()=>{const[v,setV]=useState([]);const cloudAudioRef=useRef(null);const cloudPlayingRef=useRef(false);const onSpeakRef=useRef(null);const onDoneRef=useRef(null);const[ttsKey,setTtsKey]=useState("");
  useEffect(()=>{(async()=>{try{const r=await window.storage.get("lg4_tts_key");if(r?.value)setTtsKey(r.value);}catch(e){}})();},[]);
  const saveTtsKey=useCallback(async(key)=>{setTtsKey(key);try{await window.storage.set("lg4_tts_key",key);}catch(e){}},[]);
  useEffect(()=>{const l=()=>{const x=speechSynthesis.getVoices();if(x.length)setV(x);};l();speechSynthesis.onvoiceschanged=l;return()=>{speechSynthesis.onvoiceschanged=null;};},[]);
  const getV=useCallback(()=>{const prefs=["Microsoft Jenny","Samantha","Google UK English Female","Karen","Zira"];for(const n of prefs){const x=v.find(y=>y.name.includes(n)&&y.lang.startsWith("en"));if(x)return x;}return v.find(x=>x.lang.startsWith("en"))||v[0];},[v]);
  const speakBrowser=useCallback((t,o={})=>new Promise(r=>{const u=new SpeechSynthesisUtterance(t);const voice=getV();if(voice)u.voice=voice;u.rate=o.rate||0.92;u.pitch=o.pitch||1.05;u.lang="en-US";u.volume=1;u.onend=()=>{if(onDoneRef.current)onDoneRef.current();r();};u.onerror=()=>r();speechSynthesis.cancel();setTimeout(()=>{try{speechSynthesis.speak(u);}catch(e){r();}},250);}),[getV]);
  const speak=useCallback((t,o={})=>{if(onSpeakRef.current)onSpeakRef.current(t);return speakBrowser(t,o);},[speakBrowser]);
  const stopAll=useCallback(()=>{speechSynthesis.cancel();if(cloudAudioRef.current){cloudAudioRef.current.pause();cloudAudioRef.current=null;}cloudPlayingRef.current=false;},[]);
  return{speak,stop:stopAll,onSpeakRef,onDoneRef,cloudPlayingRef,ttsKey,saveTtsKey};
};

const useRec=()=>{const[on,setOn]=useState(false);const[txt,setTxt]=useState("");const[err,setErr]=useState("");const[countdown,setCountdown]=useState(0);const[vol,setVol]=useState(0);const[phase,setPhase]=useState("idle");const[engineUsed,setEngineUsed]=useState("none");const supported=typeof navigator!=="undefined"&&!!(window.SpeechRecognition||window.webkitSpeechRecognition);const cbRef=useRef(null);const deliveredRef=useRef(false);const webRecRef=useRef(null);const cdRef=useRef(null);const hardTimerRef=useRef(null);
  const beep=useCallback((freq=880,dur=150)=>{try{const ctx=new(window.AudioContext||window.webkitAudioContext)();const osc=ctx.createOscillator(),gain=ctx.createGain();osc.type="sine";osc.frequency.value=freq;gain.gain.value=0.3;osc.connect(gain);gain.connect(ctx.destination);osc.start();gain.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+dur/1000);osc.stop(ctx.currentTime+dur/1000);setTimeout(()=>ctx.close(),dur+100);}catch(e){}},[]);
  const cleanup=useCallback(()=>{clearInterval(cdRef.current);clearTimeout(hardTimerRef.current);try{webRecRef.current?.abort();}catch(e){}webRecRef.current=null;},[]);
  const deliver=useCallback((transcript,alternatives)=>{if(deliveredRef.current)return;deliveredRef.current=true;cleanup();const result=transcript||"";if(result)beep(800,100);else beep(400,200);setTxt(result);setPhase("done");setOn(false);setCountdown(0);setVol(0);setTimeout(()=>cbRef.current?.(result,alternatives||[]),100);},[cleanup,beep]);
  const start=useCallback(async(cb,expected)=>{cleanup();cbRef.current=cb;deliveredRef.current=false;setTxt("");setErr("");setVol(0);setPhase("idle");setEngineUsed("web");
    try{speechSynthesis.cancel();}catch(e){}await new Promise(r=>setTimeout(r,200));
    const SR=window.SpeechRecognition||window.webkitSpeechRecognition;
    if(!SR){setErr("Speech not supported");return;}
    beep(1200,120);await new Promise(r=>setTimeout(r,200));
    const r=new SR();r.continuous=false;r.interimResults=true;r.lang="en-US";r.maxAlternatives=5;webRecRef.current=r;
    let best="";const alts=[];let hasFinal=false;
    r.onresult=(e)=>{let final="",interim="";for(let i=0;i<e.results.length;i++){for(let a=0;a<e.results[i].length;a++){const t=e.results[i][a].transcript.toLowerCase().trim();if(t&&!alts.includes(t))alts.push(t);}if(e.results[i].isFinal){final+=e.results[i][0].transcript;hasFinal=true;}else interim+=e.results[i][0].transcript;}const current=(final||interim).toLowerCase().trim();if(current){best=current;setTxt(current);}if(hasFinal&&best&&!deliveredRef.current){clearInterval(cdRef.current);clearTimeout(hardTimerRef.current);deliver(best,alts);}};
    r.onspeechstart=()=>setVol(0.6);r.onspeechend=()=>setVol(0.15);r.onaudiostart=()=>setVol(0.25);
    r.onend=()=>{if(!deliveredRef.current){if(best)deliver(best,alts);else setTimeout(()=>{if(!deliveredRef.current)deliver("",[]);},500);}};
    r.onerror=(e)=>{if(e.error==="not-allowed"){setErr("Microphone blocked");deliveredRef.current=true;setOn(false);setPhase("idle");}};
    try{r.start();}catch(e){try{const s=await navigator.mediaDevices.getUserMedia({audio:true});s.getTracks().forEach(t=>t.stop());r.start();}catch(e2){setErr("Mic denied");setOn(false);setPhase("idle");return;}}
    setOn(true);setPhase("listening");let sec=7;setCountdown(7);cdRef.current=setInterval(()=>{sec--;setCountdown(Math.max(0,sec));if(sec<=0)clearInterval(cdRef.current);},1000);
    hardTimerRef.current=setTimeout(()=>{if(!deliveredRef.current){try{r.stop();}catch(e){}setTimeout(()=>{if(!deliveredRef.current)deliver(best||"",[]);},1000);}},8000);
  },[beep,deliver,cleanup]);
  const stop=useCallback(()=>{cleanup();deliveredRef.current=true;setOn(false);setCountdown(0);setVol(0);setPhase("idle");},[cleanup]);
  return{start,stop,on,txt,err,countdown,vol,phase,supported,engineUsed};
};

const useStore=()=>{const[d,setD]=useState(null);const[ok,setOk]=useState(false);useEffect(()=>{(async()=>{try{const r=await window.storage.get("lg4");if(r?.value)setD(JSON.parse(r.value));}catch(e){}setOk(true);})();},[]);const save=useCallback(async(nd)=>{setD(nd);try{await window.storage.set("lg4",JSON.stringify(nd));}catch(e){}},[]);return{data:d,save,loaded:ok};};

