  const genMath=(overrideRange,overrideOp)=>{const range=overrideRange||mathRange;const opSel=overrideOp||mathOp;const[rMin,rMax]=range.split("-").map(Number);let op;if(opSel==="mix")op=["+","-","×"][Math.floor(Math.random()*3)];else op=opSel;let a,b,answer;if(op==="+"){a=rMin+Math.floor(Math.random()*(rMax-rMin+1));b=rMin+Math.floor(Math.random()*(rMax/2));answer=a+b;}else if(op==="-"){a=rMin+Math.floor(Math.random()*(rMax-rMin+1));b=rMin+Math.floor(Math.random()*Math.min(a,rMax/2));if(a<b){const t=a;a=b;b=t;}answer=a-b;}else{a=Math.max(1,rMin)+Math.floor(Math.random()*Math.min(rMax,12));b=1+Math.floor(Math.random()*10);answer=a*b;}const choices=new Set([answer]);while(choices.size<4){const w=answer+Math.floor(Math.random()*7)-3;if(w>=0&&w!==answer)choices.add(w);}setMathProblem({a,b,op,answer});setMathChoices(shuffle([...choices]));setMathFb(null);setMathAnswer(null);speak(`What is ${a} ${op==="+"?"plus":op==="-"?"minus":"times"} ${b}?`,{rate:0.8});};
