  const onMatchTap=async(tappedLetter)=>{if(matchWrong||matchCorrect)return;const currentCap=matchPairs[matchIdx]?.cap;if(!currentCap)return;stop();const isCorrect=tappedLetter.toUpperCase()===currentCap.toUpperCase();if(isCorrect){setMatchCorrect(tappedLetter);setMatchDone(p=>[...p,currentCap]);setMatchScore(s=>s+1);boom();await speak(currentCap+"! Yes!",{rate:0.85});await wait(600);setMatchCorrect(null);await advanceMatch(matchIdx+1,matchPairs);}else{setMatchWrong(tappedLetter);setMatchCorrect(currentCap);flashWrong();await speak("Oops! We need "+currentCap+".",{rate:0.8});await wait(1500);setMatchWrong(null);setMatchCorrect(null);setMatchDone(p=>[...p,currentCap]);await advanceMatch(matchIdx+1,matchPairs);}};

