  const arenaCreateRoom=()=>{if(!fbReady)return;const roomCode=genRoomCode();const me={id:arenaId,name:arenaName||prof?.name||"Player 1",avatar:ARENA_AVATARS[0],color:ARENA_COLORS[0],isHost:true};const room={code:roomCode,players:{[arenaId]:me},playerOrder:[arenaId],hostId:arenaId,state:"waiting",question:null,turnIdx:0,turnPlayerId:arenaId,scores:{[arenaId]:0},round:0,maxRounds:arenaRounds,diff:arenaDiff,createdAt:Date.now()};fbWrite("rooms/"+roomCode,room).then(()=>{setArenaRoom({...room,players:[me]});setArenaPhase("lobby");const unsub=fbListen("rooms/"+roomCode,onRoomData,onRoomDeleted);fbListenerRef.current=unsub;}).catch(e=>setFbError(e.message));};
  const arenaJoinRoom=(code)=>{if(!fbReady)return;const c=code.toUpperCase().trim();if(c.length!==6)return;const ref=fbRef("rooms/"+c);if(!ref){setFbError("Connection error");return;}ref.once("value").then(snap=>{const room=snap.val();if(!room){setFbError("Room not found!");return;}const existing=room.players?Object.values(room.players):[];if(existing.length>=4){setFbError("Room full!");return;}if(!existing.find(p=>p.id===arenaId)){const pi=existing.length;const me={id:arenaId,name:arenaName||prof?.name||"Player",avatar:ARENA_AVATARS[pi%4],color:ARENA_COLORS[pi%4],isHost:false};const newOrder=(room.playerOrder||Object.keys(room.players||{}));if(!newOrder.includes(arenaId))newOrder.push(arenaId);fbUpdate("rooms/"+c,{["players/"+arenaId]:me,["scores/"+arenaId]:0,playerOrder:newOrder});}if(fbListenerRef.current)fbListenerRef.current();const unsub=fbListen("rooms/"+c,onRoomData,onRoomDeleted);fbListenerRef.current=unsub;setArenaPhase("lobby");}).catch(e=>setFbError(e.message));};
