  useEffect(()=>{const rm=arenaRoomRef.current||arenaRoom;if(!rm||rm.hostId!==arenaId||rm.state!=="playing")return;const la=rm.lastAnswer;if(!la||la.round!==rm.round||la.turnIdx!==rm.turnIdx)return;const players=rm.players||[];const nextIdx=((rm.turnIdx||0)+1)%players.length;if(nextIdx===0)fbUpdate("rooms/"+rm.code,{state:"result",answerBy:null});else fbUpdate("rooms/"+rm.code,{turnIdx:nextIdx,turnPlayerId:players[nextIdx]?.id,turnStartedAt:Date.now(),lastAnswer:null});},[arenaRoom?.lastAnswer?.ts]);
